mapper.sql:
WHERE o.tenant_id = #{tenantId}

  AND (
    o.object_code LIKE CONCAT('%', #{query.keyword}, '%')
    OR o.object_name LIKE CONCAT('%', #{query.keyword}, '%')
    OR o.description LIKE CONCAT('%', #{query.keyword}, '%')
    OR o.model_code LIKE CONCAT('%', #{query.keyword}, '%')
  )


  AND o.suite_code = #{query.suiteCode}


  AND o.object_code = #{query.objectCode}


  AND o.object_type = #{query.objectType}


  AND o.model_code = #{query.modelCode}


  AND o.status = #{query.status}

mapper.select:

WHERE o.tenant_id = #{tenantId}
  AND o.suite_code = #{suiteCode}
  AND o.object_code = #{objectCode}
LIMIT 1

SELECT

FROM ai_business_object
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND object_code = #{objectCode}
LIMIT 1

SELECT COUNT(1)
FROM ai_business_object
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND object_code = #{objectCode}

  AND id != #{excludeId}

SELECT COUNT(1)
FROM ai_business_object_relation
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND (source_object_code = #{objectCode} OR target_object_code = #{objectCode})

SELECT COUNT(1)
FROM ai_business_app
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
  AND object_code = #{objectCode}

SELECT COUNT(1)
FROM ai_business_binding
WHERE tenant_id = #{tenantId}
  AND target_type = 'OBJECT'
  AND target_code = #{objectCode}

SELECT

FROM ai_business_object
WHERE tenant_id = #{tenantId}
  AND suite_code = #{suiteCode}
ORDER BY sort_order ASC, id ASC
